const now = new Date();
const windowStart = new Date(now.getTime() - 72 * 60 * 60 * 1000);

const pubStartDate = windowStart.toISOString().replace('.000Z', '.000');
const pubEndDate = now.toISOString().replace('.000Z', '.000');

const url = `https://services.nvd.nist.gov/rest/json/cves/2.0?pubStartDate=${pubStartDate}&pubEndDate=${pubEndDate}&resultsPerPage=2000`;

return [{
  json: {
    url,
    pubStartDate,
    pubEndDate,
    source: 'NVD',
    timestamp: now.toISOString()
  }
}];

// ============================================================
// NORMALIZE NVD DATA
// Converts NVD raw response into our standard CVE schema
// ============================================================
const input = $input.item.json;

if (!input.vulnerabilities || input.vulnerabilities.length === 0) {
  return [{ json: { cves: [], count: 0, source: 'NVD' } }];
}

const cves = input.vulnerabilities.map(item => {
  const cve = item.cve;
  const metrics = cve.metrics || {};

  // Try CVSS v3.1 first, then v3.0, then v2
  let cvssScore = 0;
  let severity = 'UNKNOWN';
  let cvssVector = '';

  if (metrics.cvssMetricV31 && metrics.cvssMetricV31.length > 0) {
    const m = metrics.cvssMetricV31[0];
    cvssScore = m.cvssData.baseScore;
    severity = m.cvssData.baseSeverity;
    cvssVector = m.cvssData.vectorString;
  } else if (metrics.cvssMetricV30 && metrics.cvssMetricV30.length > 0) {
    const m = metrics.cvssMetricV30[0];
    cvssScore = m.cvssData.baseScore;
    severity = m.cvssData.baseSeverity;
    cvssVector = m.cvssData.vectorString;
  } else if (metrics.cvssMetricV2 && metrics.cvssMetricV2.length > 0) {
    const m = metrics.cvssMetricV2[0];
    cvssScore = m.cvssData.baseScore;
    severity = m.baseSeverity || 'MEDIUM';
    cvssVector = m.cvssData.vectorString;
  }

  // Extract affected products
  const affected_products = [];
  if (cve.configurations) {
    cve.configurations.forEach(config => {
      if (config.nodes) {
        config.nodes.forEach(node => {
          if (node.cpeMatch) {
            node.cpeMatch.forEach(cpe => {
              if (cpe.vulnerable) {
                affected_products.push(cpe.criteria);
              }
            });
          }
        });
      }
    });
  }

  // Get English description
  const description = cve.descriptions
    ? (cve.descriptions.find(d => d.lang === 'en') || {}).value || 'No description available'
    : 'No description available';

  // Get references
  const references = cve.references
    ? cve.references.slice(0, 5).map(r => r.url)
    : [];

  return {
    cve_id: cve.id,
    source: 'NVD',
    title: `${cve.id} — ${severity} Vulnerability`,
    description: description,
    cvss_score: cvssScore,
    cvss_vector: cvssVector,
    severity: severity,
    affected_products: affected_products.slice(0, 10),
    references: references,
    published_at: cve.published,
    modified_at: cve.lastModified,
    is_cisa_kev: false,
    has_exploit: false,
    epss_score: 0,
    priority_score: 0,
    category: 'UNCATEGORIZED',
    ai_summary: '',
    ai_classification: null,
    correlation_data: null,
    normalized_at: new Date().toISOString()
  };
});

return [{ json: { cves, count: cves.length, source: 'NVD' } }];

// ============================================================
// NORMALIZE OTX DATA
// Extracts CVE references from AlienVault OTX pulses
// ============================================================
const input = $input.item.json;

if (!input.results || input.results.length === 0) {
  return [{ json: { cves: [], count: 0, source: 'OTX' } }];
}

const cves = [];

input.results.forEach(pulse => {
  // Extract CVE indicators from pulse
  const cveIndicators = (pulse.indicators || []).filter(ind => ind.type === 'CVE');

  cveIndicators.forEach(ind => {
    cves.push({
      cve_id: ind.indicator,
      source: 'OTX',
      title: `${ind.indicator} — from OTX Pulse: ${pulse.name}`,
      description: pulse.description || ind.description || 'Threat intelligence from AlienVault OTX',
      cvss_score: 0,
      cvss_vector: '',
      severity: 'UNKNOWN',
      affected_products: pulse.tags || [],
      references: [pulse.references?.[0] || ''].filter(Boolean),
      published_at: ind.created || pulse.created,
      modified_at: pulse.modified,
      is_cisa_kev: false,
      has_exploit: pulse.adversary ? true : false,
      epss_score: 0,
      priority_score: 0,
      category: 'UNCATEGORIZED',
      otx_pulse_name: pulse.name,
      otx_adversary: pulse.adversary || '',
      otx_targeted_countries: pulse.targeted_countries || [],
      otx_industries: pulse.industries || [],
      ai_summary: '',
      ai_classification: null,
      normalized_at: new Date().toISOString()
    });
  });
});

return [{ json: { cves, count: cves.length, source: 'OTX' } }];

// ============================================================
// NORMALIZE CISA KEV DATA
// Marks CVEs as actively exploited
// ============================================================
const input = $input.item.json;

if (!input.vulnerabilities || input.vulnerabilities.length === 0) {
  return [{ json: { cves: [], count: 0, source: 'CISA_KEV' } }];
}

// Only take entries added in the last 7 days
const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);

const cves = input.vulnerabilities
  .filter(v => new Date(v.dateAdded) >= sevenDaysAgo)
  .map(v => ({
    cve_id: v.cveID,
    source: 'CISA_KEV',
    title: `${v.cveID} — ${v.vulnerabilityName}`,
    description: v.shortDescription || v.vulnerabilityName,
    cvss_score: 0,
    cvss_vector: '',
    severity: 'HIGH',
    affected_products: [`${v.vendorProject} ${v.product}`],
    references: [],
    published_at: v.dateAdded,
    modified_at: v.dateAdded,
    is_cisa_kev: true,
    has_exploit: true,
    cisa_due_date: v.dueDate,
    cisa_required_action: v.requiredAction,
    epss_score: 0,
    priority_score: 9.5,
    category: 'ACTIVELY_EXPLOITED',
    ai_summary: '',
    ai_classification: null,
    normalized_at: new Date().toISOString()
  }));

return [{ json: { cves, count: cves.length, source: 'CISA_KEV' } }];

const allInputs = $input.all();

const allCves = [];
const seenIds = new Set();

allInputs.forEach(input => {
  const data = input.json;
  if (data.cves && Array.isArray(data.cves)) {
    data.cves.forEach(cve => {
      if (cve.cve_id && cve.cve_id !== 'undefined' && !seenIds.has(cve.cve_id)) {
        seenIds.add(cve.cve_id);
        allCves.push(cve);
      } else if (cve.cve_id && seenIds.has(cve.cve_id)) {
        const existing = allCves.find(c => c.cve_id === cve.cve_id);
        if (existing && cve.is_cisa_kev) {
          existing.is_cisa_kev = true;
          existing.priority_score = Math.max(existing.priority_score, 9.5);
          existing.has_exploit = true;
        }
      }
    });
  }
});

console.log(`[COLLECTOR] Total unique CVEs collected: ${allCves.length}`);

if (allCves.length === 0) {
  return [];
}

return allCves.map(cve => ({ json: cve }));

// ============================================================
// AGENT 2 — ENRICHER (Part A)
// Fetch EPSS score for this CVE
// EPSS = Exploit Prediction Scoring System
// Tells us probability of exploitation in next 30 days
// ============================================================
const cve = $input.item.json;

return [{
  json: {
    ...cve,
    epss_url: `https://api.first.org/data/v1/epss?cve=${cve.cve_id}`
  }
}];

// ============================================================
// MERGE EPSS SCORE BACK INTO CVE
// ============================================================
const epssResponse = $input.item.json;

// Get the CVE data from previous step in chain
// EPSS API returns: { data: [{ cve, epss, percentile, date }] }
let epssScore = 0;
let epssPercentile = 0;

if (epssResponse.data && epssResponse.data.length > 0) {
  epssScore = parseFloat(epssResponse.data[0].epss) || 0;
  epssPercentile = parseFloat(epssResponse.data[0].percentile) || 0;
}

// Pass along all previous CVE data
const previousCve = $('Build EPSS URL').item.json;

return [{
  json: {
    ...previousCve,
    epss_score: epssScore,
    epss_percentile: epssPercentile,
    epss_fetched_at: new Date().toISOString()
  }
}];

// ============================================================
// AGENT 2 — ENRICHER (Part B)
// Build Groq API prompt for rapid CVE classification
// ============================================================
const cve = $input.item.json;

const prompt = `You are a senior cybersecurity analyst. Analyze this CVE and respond ONLY with valid JSON, no markdown, no explanation.

CVE ID: ${cve.cve_id}
Severity: ${cve.severity}
CVSS Score: ${cve.cvss_score}
Description: ${cve.description}
Affected Products: ${JSON.stringify(cve.affected_products?.slice(0, 5))}
Is CISA KEV (Actively Exploited): ${cve.is_cisa_kev}
EPSS Score (exploitation probability): ${cve.epss_score}

Respond with this exact JSON structure:
{
  "category": "one of: Web Application | Network Protocol | Operating System | Database | Library/Framework | Cloud/Container | IoT/Embedded | Hardware | Cryptography | Authentication",
  "attack_type": "e.g. Remote Code Execution | SQL Injection | Buffer Overflow | Privilege Escalation | XSS | CSRF | Path Traversal | Denial of Service | Information Disclosure",
  "attack_complexity": "Low | Medium | High",
  "requires_authentication": true or false,
  "network_exploitable": true or false,
  "likely_targets": ["list of 2-3 industries most at risk"],
  "urgency": "CRITICAL | HIGH | MEDIUM | LOW",
  "plain_english_summary": "2-3 sentence explanation a non-technical person can understand",
  "technical_impact": "what an attacker can achieve if they exploit this",
  "recommended_action": "immediate action to take (patch version, workaround, etc)"
}`;

return [{
  json: {
    ...cve,
    groq_prompt: prompt
  }
}];

// ============================================================
// PARSE GROQ CLASSIFICATION RESPONSE
// ============================================================
const groqResponse = $input.item.json;
const previousCve = $('Build Groq Prompt').item.json;

let classification = null;
try {
  const content = groqResponse.choices?.[0]?.message?.content || '{}';
  classification = JSON.parse(content);
} catch (e) {
  console.error('[ENRICHER] Failed to parse Groq response:', e.message);
  classification = {
    category: 'UNCATEGORIZED',
    attack_type: 'Unknown',
    attack_complexity: 'Unknown',
    requires_authentication: false,
    network_exploitable: true,
    likely_targets: [],
    urgency: previousCve.severity || 'MEDIUM',
    plain_english_summary: previousCve.description?.substring(0, 200) || '',
    technical_impact: 'Unknown',
    recommended_action: 'Check vendor advisory'
  };
}

// ============================================================
// CALCULATE COMPOSITE PRIORITY SCORE
// Formula: (CVSS × 0.30) + (EPSS × 0.25) + (CISA_KEV × 0.20) 
//        + (Exploit_Available × 0.15) + (Network_Exploitable × 0.10)
// ============================================================
const cvssNorm = (previousCve.cvss_score || 0) / 10;
const epssNorm = previousCve.epss_score || 0;
const cisaBonus = previousCve.is_cisa_kev ? 1 : 0;
const exploitBonus = previousCve.has_exploit ? 1 : 0;
const networkBonus = classification.network_exploitable ? 1 : 0;

const priorityScore = (
  (cvssNorm * 0.30) +
  (epssNorm * 0.25) +
  (cisaBonus * 0.20) +
  (exploitBonus * 0.15) +
  (networkBonus * 0.10)
) * 10;

const finalPriority = Math.min(10, parseFloat(priorityScore.toFixed(2)));

const enrichedCve = {
  ...previousCve,
  ai_classification: classification,
  category: classification.category || 'UNCATEGORIZED',
  attack_type: classification.attack_type || 'Unknown',
  urgency: classification.urgency || previousCve.severity || 'MEDIUM',
  plain_english_summary: classification.plain_english_summary || '',
  technical_impact: classification.technical_impact || '',
  recommended_action: classification.recommended_action || '',
  priority_score: finalPriority,
  enriched_at: new Date().toISOString()
};

console.log(`[ENRICHER] ${enrichedCve.cve_id} | Priority: ${finalPriority} | Urgency: ${enrichedCve.urgency}`);

return [{ json: enrichedCve }];

// ============================================================
// AGENT 3 — CORRELATOR (Part A)
// Build Gemini prompt to find correlations with known threats
// ============================================================
const cve = $input.item.json;

const geminiPrompt = `You are a threat intelligence analyst with expertise in vulnerability research and threat actor profiling.

Analyze this CVE and provide correlation intelligence. Respond ONLY with valid JSON.

CVE: ${cve.cve_id}
Category: ${cve.category}
Attack Type: ${cve.attack_type}
Description: ${cve.description}
Affected Products: ${JSON.stringify(cve.affected_products?.slice(0, 5))}
CVSS Score: ${cve.cvss_score}
EPSS Score: ${cve.epss_score}
Is CISA KEV: ${cve.is_cisa_kev}
Technical Impact: ${cve.technical_impact}

Respond with this exact JSON:
{
  "related_cve_patterns": ["2-3 CVE patterns or types that are commonly chained with this attack type"],
  "likely_threat_actors": [
    {
      "name": "threat actor name (e.g. APT28, Lazarus Group, FIN7)",
      "reason": "why this actor would be interested",
      "origin": "country or organization"
    }
  ],
  "attack_chain_potential": {
    "can_chain": true or false,
    "chain_description": "how this CVE fits into a larger attack chain",
    "chain_entry_point": true or false,
    "chain_payload": true or false
  },
  "mitre_attack_techniques": ["T1xxx technique IDs that match this vulnerability"],
  "targeted_industries": ["industries most likely to be targeted"],
  "exploitation_timeline": "immediate (exploit exists) | near-term (30 days) | medium-term (90 days) | long-term (6+ months)",
  "correlation_confidence": 0.0 to 1.0,
  "analyst_notes": "additional intelligence context a security team should know"
}`;

return [{
  json: {
    ...cve,
    gemini_prompt: geminiPrompt
  }
}];

// ============================================================
// PARSE GEMINI CORRELATION RESPONSE
// ============================================================
const geminiResponse = $input.item.json;
const previousCve = $('Build Gemini Prompt').item.json;

let correlationData = null;
try {
  const content = geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  correlationData = JSON.parse(content);
} catch (e) {
  console.error('[CORRELATOR] Failed to parse Gemini response:', e.message);
  correlationData = {
    related_cve_patterns: [],
    likely_threat_actors: [],
    attack_chain_potential: { can_chain: false },
    mitre_attack_techniques: [],
    targeted_industries: previousCve.ai_classification?.likely_targets || [],
    exploitation_timeline: 'unknown',
    correlation_confidence: 0.5,
    analyst_notes: 'Correlation analysis unavailable'
  };
}

// Boost priority score if high-confidence threat actor correlation found
let adjustedPriority = previousCve.priority_score;
if (correlationData.correlation_confidence > 0.8 && 
    correlationData.likely_threat_actors?.length > 0) {
  adjustedPriority = Math.min(10, adjustedPriority + 0.5);
}
if (correlationData.attack_chain_potential?.can_chain) {
  adjustedPriority = Math.min(10, adjustedPriority + 0.3);
}

const correlatedCve = {
  ...previousCve,
  correlation_data: correlationData,
  threat_actors: correlationData.likely_threat_actors || [],
  mitre_techniques: correlationData.mitre_attack_techniques || [],
  attack_chain: correlationData.attack_chain_potential || {},
  exploitation_timeline: correlationData.exploitation_timeline || 'unknown',
  priority_score: parseFloat(adjustedPriority.toFixed(2)),
  correlated_at: new Date().toISOString()
};

console.log(`[CORRELATOR] ${correlatedCve.cve_id} | Threat Actors: ${correlatedCve.threat_actors.length} | Chain: ${correlatedCve.attack_chain?.can_chain}`);

return [{ json: correlatedCve }];

// ============================================================
// AGENT 5 — DISPATCHER (Immediate Alert)
// Fires instantly for CRITICAL CVEs (score >= 8.5)
// ============================================================
const cve = $input.item.json;

// Severity emoji map
const severityEmoji = {
  'CRITICAL': '🔴',
  'HIGH': '🟠', 
  'MEDIUM': '🟡',
  'LOW': '🟢',
  'UNKNOWN': '⚪'
};

const emoji = severityEmoji[cve.urgency] || '⚠️';
const kevBadge = cve.is_cisa_kev ? '\n⚡ ACTIVELY EXPLOITED (CISA KEV)' : '';
const chainBadge = cve.attack_chain?.can_chain ? '\n🔗 Attack chain potential detected' : '';

const threatActorText = cve.threat_actors && cve.threat_actors.length > 0
  ? `\n👥 Linked threat actors: ${cve.threat_actors.slice(0,2).map(a => a.name).join(', ')}`
  : '';

const mitreText = cve.mitre_techniques && cve.mitre_techniques.length > 0
  ? `\n🎯 MITRE ATT&CK: ${cve.mitre_techniques.slice(0,3).join(', ')}`
  : '';

const message = `${emoji} *CRITICAL ALERT — CyberWatch*

*${cve.cve_id}*
${cve.title || cve.cve_id}${ kevBadge}${chainBadge}

📊 *Scores*
• CVSS: ${cve.cvss_score}/10
• EPSS: ${(cve.epss_score * 100).toFixed(1)}% exploitation probability
• Priority: ${cve.priority_score}/10

📝 *What this means*
${cve.plain_english_summary || cve.description?.substring(0, 300) || 'See full report'}

💥 *Attack type:* ${cve.attack_type || 'Unknown'}
🏭 *Category:* ${cve.category || 'Unknown'}${threatActorText}${mitreText}

✅ *Recommended action*
${cve.recommended_action || 'Check vendor advisory immediately'}

⏱️ *Timeline:* ${cve.exploitation_timeline || 'Unknown'}
🕐 Detected: ${new Date().toLocaleString('en-IN', {timeZone: 'Asia/Kolkata'})}`;

return [{
  json: {
    ...cve,
    telegram_message: message,
    alert_type: 'IMMEDIATE_CRITICAL'
  }
}];

// ============================================================
// AGENT 4 — PRIORITIZER
// Runs at 8AM — Fetches today's CVEs and ranks them
// Generates a daily digest
// ============================================================
const trigger = $input.item.json;

// This will query our database for yesterday/today's CVEs
// We prepare the query
const since = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString();

return [{
  json: {
    query_since: since,
    generated_at: new Date().toISOString(),
    trigger_type: 'DAILY_DIGEST'
  }
}];

// ============================================================
// AGENT 4 — PRIORITIZER (continued)
// Groups CVEs by severity and formats digest
// ============================================================
const allItems = $input.all();
const cves = allItems.map(item => item.json);

if (cves.length === 0 || (cves.length === 1 && !cves[0].cve_id)) {
  return [{
    json: {
      message: 'No CVEs to report today.',
      critical: [], high: [], medium: [], low: [],
      total: 0
    }
  }];
}

// Group by urgency
const groups = { CRITICAL: [], HIGH: [], MEDIUM: [], LOW: [], UNKNOWN: [] };

cves.forEach(cve => {
  const urgency = cve.urgency || 'UNKNOWN';
  if (groups[urgency]) {
    groups[urgency].push(cve);
  } else {
    groups.UNKNOWN.push(cve);
  }
});

// Sort each group by priority_score
Object.keys(groups).forEach(key => {
  groups[key].sort((a, b) => (b.priority_score || 0) - (a.priority_score || 0));
});

// Top CVEs to highlight
const topCritical = groups.CRITICAL.slice(0, 5);
const topHigh = groups.HIGH.slice(0, 5);
const topMedium = groups.MEDIUM.slice(0, 3);

// Stats
const stats = {
  total: cves.length,
  critical: groups.CRITICAL.length,
  high: groups.HIGH.length,
  medium: groups.MEDIUM.length,
  low: groups.LOW.length,
  cisa_kev: cves.filter(c => c.is_cisa_kev).length,
  with_exploit: cves.filter(c => c.has_exploit).length,
  with_threat_actors: cves.filter(c => {
    try { return JSON.parse(c.threat_actors || '[]').length > 0; } catch(e) { return false; }
  }).length
};

return [{
  json: {
    stats,
    topCritical,
    topHigh,
    topMedium,
    allGroups: groups,
    generated_at: new Date().toISOString()
  }
}];

