// ============================================================
// AGENT 5 — DISPATCHER (Daily Digest)
// Formats the beautiful morning Telegram digest
// ============================================================
const geminiResponse = $input.item.json;
const digestData = $('Group & Rank CVEs').item.json;

// Extract Gemini summary
const execSummary = geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text 
  || 'Daily threat intelligence digest ready.';

const stats = digestData.stats;
const topCritical = digestData.topCritical || [];
const topHigh = digestData.topHigh || [];

// Format date in IST
const dateStr = new Date().toLocaleDateString('en-IN', {
  timeZone: 'Asia/Kolkata',
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});

// Build critical CVE lines
const criticalLines = topCritical.slice(0, 5).map((cve, i) => {
  const kevTag = cve.is_cisa_kev ? ' ⚡' : '';
  const exploitTag = cve.has_exploit ? ' 💣' : '';
  return `${i + 1}. *${cve.cve_id}*${kevTag}${exploitTag}
   └ ${cve.attack_type || 'Unknown'} | Score: ${cve.priority_score}/10
   └ ${(cve.plain_english_summary || cve.description || '').substring(0, 100)}...`;
}).join('\n\n');

// Build high CVE lines
const highLines = topHigh.slice(0, 3).map((cve, i) => {
  return `${i + 1}. *${cve.cve_id}* — ${cve.attack_type || 'Unknown'} (${cve.priority_score}/10)`;
}).join('\n');

const message = `🛡️ *CyberWatch Daily Brief*
📅 ${dateStr}
${'─'.repeat(30)}

📊 *Today's Numbers*
• Total new CVEs: *${stats.total}*
• 🔴 Critical: *${stats.critical}*
• 🟠 High: *${stats.high}*
• 🟡 Medium: *${stats.medium}*
• ⚡ CISA KEV (active attacks): *${stats.cisa_kev}*
• 💣 Public exploits available: *${stats.with_exploit}*
${'─'.repeat(30)}

🤖 *AI Executive Summary*
${execSummary}
${'─'.repeat(30)}

🔴 *TOP CRITICAL THREATS*
${criticalLines || 'No critical CVEs today ✅'}
${'─'.repeat(30)}

${topHigh.length > 0 ? `🟠 *TOP HIGH SEVERITY*
${highLines}
${'─'.repeat(30)}

` : ''}⚡ = Actively exploited | 💣 = Public exploit available

🕐 Generated: ${new Date().toLocaleTimeString('en-IN', {timeZone: 'Asia/Kolkata'})} IST
📡 Sources: NVD • OTX • CISA KEV • OSV.dev`;

return [{
  json: {
    digest_message: message,
    stats: digestData.stats,
    generated_at: new Date().toISOString(),
    alert_type: 'DAILY_DIGEST'
  }
}];

// ============================================================
// LOG COMPLETED RUN
// ============================================================
const result = $input.item.json;
console.log(`[DISPATCHER] Daily digest sent. Stats: ${JSON.stringify(result.stats)}`);
return [{ json: { status: 'SUCCESS', message: 'Daily digest delivered', ...result } }];

